package baritone.api.utils;

/**
 * Small compatibility replacement for the Mojang Tuple removed in Minecraft
 * 26.2.
 */
public final class Tuple<A, B> {

    private final A a;
    private final B b;

    public Tuple(A a, B b) {
        this.a = a;
        this.b = b;
    }

    public A getA() {
        return a;
    }

    public B getB() {
        return b;
    }
}
